import { domToReact } from "html-react-parser";
import type { ReplaceHandler } from "./types";

/**
 * Tiptap-style WYSIWYG editors sometimes emit non-standard block tags
 * (e.g. `<card>`, `<callout>`, `<note>`, `<tip>`, `<warning>`) when an
 * operator drops a custom "info box" extension into the article. Those
 * tags reach the visitor surface verbatim — browsers don't know what
 * to do with them (render as inline, no styling), and React in dev
 * surfaces:
 *
 *     The tag <card> is unrecognized in this browser.
 *
 * Rather than leak the warning + an unstyled blob to the visitor, we
 * map these known structural tags to a tonal `<div>` shell that
 * matches the widget's card chrome — keeps the operator's intent
 * (visually-distinct callout) without the lint noise. Children pass
 * through `domToReact` so nested content (paragraphs, links, lists)
 * still gets the full replace pipeline (links open with the right
 * referrer policy, images join the lightbox gallery, etc.).
 *
 * Each tag picks a quiet accent colour so a `<warning>` and a
 * `<note>` don't look identical — the visual hierarchy survives even
 * when we don't know the operator's exact intent.
 */
const CUSTOM_TAGS: Record<string, string> = {
  card: "border-wx-border bg-wx-bg-elevated/60",
  callout: "border-wx-primary/30 bg-wx-primary/5",
  note: "border-wx-border bg-wx-bg-elevated/60",
  tip: "border-wx-success/30 bg-wx-success/5",
  warning: "border-wx-warning/30 bg-wx-warning/5",
  danger: "border-wx-danger/30 bg-wx-danger/5",
};

export const customElementHandler: ReplaceHandler = (node, ctx) => {
  const tone = CUSTOM_TAGS[node.name];
  if (!tone) return undefined;
  return (
    <div className={`my-4 rounded-wx-md border px-4 py-3 ${tone}`} data-custom-block={node.name}>
      {domToReact((node.children ?? []) as Parameters<typeof domToReact>[0], ctx.options)}
    </div>
  );
};
