"use client";

import parse from "html-react-parser";
import { type ReactNode, useMemo, useState } from "react";
import {
  type LightboxItem,
  MediaLightbox,
} from "@/components/widget/tabs/messages-tab/message/media-lightbox";
import type { TocEntry } from "@/lib/article-toc";
import { TableOfContents } from "./blocks/table-of-contents";
import { buildOptions } from "./build-options";

/**
 * Renders operator-authored HTML (TipTap output) and RSS-ingested
 * `<content:encoded>` into a React tree, swapping selected tags for
 * proper React components.
 *
 * Why a parser instead of `dangerouslySetInnerHTML`: TipTap emits
 * custom blocks for tabs + accordions that need interactive state
 * (active tab, expand/collapse). Doing this with raw HTML + a DOM
 * walk in `useEffect` works but ties the markup to imperative
 * post-render mutations. Parsing once into React lets the same
 * components live alongside the rest of the widget tree, with full
 * styling and a11y at the React layer.
 *
 * Custom mappings live in `build-options/` — one file per tag:
 *   - `<div data-type="tabs">` → `TabsBlock` with active-tab state
 *   - `<details>` / TipTap details → `AccordionBlock` with open state
 *   - `<table>`                → wrapped in a horizontal scroll container
 *   - `<img>`                  → width + alignment honoured
 *   - `<a>`                    → forced `target="_blank" rel="noopener"`
 *   - `h1`/`h2`/`h3`           → slugged id + pushed to the TOC
 *
 * Everything else falls through to the parser's default mapping
 * (paragraphs, lists, code, images, figures, …). Those land in the
 * surrounding `prose` class string for styling.
 */
export function ArticleHtml({ html, className }: { html: string; className?: string }) {
  // Parse once per render, building the TOC as a side effect of the
  // heading handler. Three+ headings warrant a dropdown; anything less
  // and the post is short enough to scroll without help.
  //
  // Memoised on `html`: `parse()` walks + transforms the whole markup
  // tree (real main-thread work), so we only redo it when the content
  // actually changes — not on every parent re-render. The `entries`
  // accumulator is filled as a side effect of parsing, so it's
  // returned from the same memo.
  // Index of the body image the visitor tapped (opens the lightbox), or
  // `null` when closed.
  const [lightboxIndex, setLightboxIndex] = useState<number | null>(null);

  const { parsed, entries, images } = useMemo(() => {
    const collected: TocEntry[] = [];
    const seenIds = new Set<string>();
    const imgs: LightboxItem[] = [];
    const tree = parse(html, buildOptions(collected, seenIds, imgs, setLightboxIndex));
    return { parsed: tree, entries: collected, images: imgs };
  }, [html]);

  return (
    <div className={className}>
      {entries.length >= 3 && <TableOfContents entries={entries} />}
      {parsed}
      {images.length > 0 && (
        // Body images open the same full-screen gallery as chat media —
        // tap to zoom, arrow / swipe to move between every image in the
        // article.
        <MediaLightbox
          items={images}
          initialIndex={lightboxIndex ?? 0}
          open={lightboxIndex !== null}
          onClose={() => setLightboxIndex(null)}
        />
      )}
    </div>
  );
}

/**
 * Standalone version of the parser for callers that don't need a TOC
 * (chat-message body rendering, peek previews). Skips the heading
 * collector closure so it stays a pure transform.
 */
export function parseArticleHtml(html: string): ReactNode {
  const noop: TocEntry[] = [];
  const seen = new Set<string>();
  return parse(html, buildOptions(noop, seen));
}
