import { domToReact, Element } from "html-react-parser";
import { TabsBlock } from "../blocks/tabs-block";
import { extractText } from "../extract-text";
import type { ReplaceHandler } from "./types";

/**
 * `<div data-type="tabs">` → `<TabsBlock>` with active-tab state. Each
 * child `<div data-type="tab">` carries a label node (the
 * `[data-tab-label]` div) as its first child; everything else is body.
 * The empty-label fallback ("Tab N") is applied in `TabsBlock` so it
 * can be translated.
 */
export const tabsHandler: ReplaceHandler = (node, ctx) => {
  const isTabs =
    node.name === "div" &&
    (node.attribs?.["data-type"] === "tabs" ||
      (node.attribs as Record<string, string> | undefined)?.["data-type"] === "tabs");
  if (!isTabs) return undefined;

  const tabChildren = (node.children ?? []).filter(
    (child): child is Element =>
      child instanceof Element && child.name === "div" && child.attribs?.["data-type"] === "tab",
  );
  const tabs = tabChildren.map((tabEl) => {
    // First child of each tab is the label node; the rest is body.
    const labelEl = tabEl.children?.find(
      (c): c is Element =>
        c instanceof Element && c.name === "div" && "data-tab-label" in (c.attribs ?? {}),
    );
    const bodyEls = (tabEl.children ?? []).filter((c) => c !== labelEl);
    const labelText = labelEl ? extractText(labelEl).trim() : "";
    return {
      label: labelText,
      body: <>{domToReact(bodyEls as Parameters<typeof domToReact>[0], ctx.options)}</>,
    };
  });
  return <TabsBlock tabs={tabs} />;
};
