/**
 * Shared Tailwind class string for article-body prose rendering.
 *
 * Used by both the help-article view and the news-article view. The
 * widget renders operator-authored HTML (TipTap output) and RSS
 * `<content:encoded>` via `dangerouslySetInnerHTML`, so styling for
 * every element the editor can emit lives here as one place to keep
 * the two surfaces consistent.
 *
 * Design target: shadcn-style chrome — rounded surfaces, hairline
 * borders, restrained palette. The widget runs inside a 420 px iframe
 * panel by default, so spacing is tighter than a desktop article
 * page; rules favour `text-sm` cadence and `gap-2` ladders.
 *
 * Keep the rules in roughly source-order of the elements they target;
 * a top-down read makes "did we cover X?" easy to grep.
 */
export const ARTICLE_PROSE_CLASSES = [
  // ─── Container baseline ─────────────────────────────────────────
  "prose max-w-none text-sm leading-relaxed text-wx-fg",

  // ─── Inline + paragraph ─────────────────────────────────────────
  "[&_p]:my-3 [&_strong]:font-semibold [&_em]:italic",
  // Links — brand-coloured underline + hover fade.
  "[&_a]:text-wx-primary [&_a]:underline [&_a]:underline-offset-2",
  "[&_a]:transition-opacity [&_a:hover]:opacity-70",
  // Inline code — pill-shaped chip on the elevated surface.
  "[&_code]:rounded-[6px] [&_code]:bg-wx-bg-elevated [&_code]:px-1.5 [&_code]:py-0.5 [&_code]:font-mono [&_code]:text-[0.85em]",

  // ─── Code blocks ────────────────────────────────────────────────
  // Dark slab with hairline border + rounded edges. Inside the
  // bubble's `<code>` reset to plain text so the inline-code chip
  // rules don't double-apply.
  "[&_pre]:my-4 [&_pre]:overflow-x-auto [&_pre]:rounded-lg [&_pre]:border [&_pre]:border-wx-border",
  "[&_pre]:bg-[#0f1115] [&_pre]:text-zinc-100 [&_pre]:p-4 [&_pre]:text-[12.5px] [&_pre]:leading-relaxed",
  "[&_pre_code]:bg-transparent [&_pre_code]:p-0 [&_pre_code]:text-zinc-100",
  // lowlight / highlight.js token colours — visible on the dark
  // slab. One-shot ramp that reads on light + dark widget themes.
  "[&_.hljs-keyword]:text-violet-300 [&_.hljs-built_in]:text-violet-300 [&_.hljs-type]:text-violet-300",
  "[&_.hljs-string]:text-emerald-300",
  "[&_.hljs-number]:text-amber-300 [&_.hljs-literal]:text-amber-300",
  "[&_.hljs-comment]:text-zinc-500 [&_.hljs-comment]:italic",
  "[&_.hljs-attr]:text-sky-300 [&_.hljs-attribute]:text-sky-300",
  "[&_.hljs-title]:text-zinc-100 [&_.hljs-title]:font-medium",
  "[&_.hljs-tag]:text-rose-300 [&_.hljs-name]:text-rose-300",

  // ─── Headings ───────────────────────────────────────────────────
  // Collapsed scale so long-form posts still feel right in the
  // 420 px panel. Tracking tightens with size — matches shadcn
  // typography defaults.
  "[&_h1]:mt-6 [&_h1]:mb-3 [&_h1]:text-xl [&_h1]:font-semibold [&_h1]:tracking-tight",
  "[&_h2]:mt-5 [&_h2]:mb-2 [&_h2]:text-base [&_h2]:font-semibold [&_h2]:tracking-tight",
  "[&_h3]:mt-4 [&_h3]:mb-1.5 [&_h3]:text-sm [&_h3]:font-semibold",
  // `scroll-margin-top` lifts the smooth-scroll target so TOC
  // clicks don't land the heading flush against the widget's
  // fixed top bar. 64 px clears the typical panel header height.
  "[&_h1]:scroll-mt-16 [&_h2]:scroll-mt-16 [&_h3]:scroll-mt-16",

  // ─── Lists ──────────────────────────────────────────────────────
  "[&_ul]:my-3 [&_ul]:list-disc [&_ul]:pl-5 [&_ul]:marker:text-wx-fg-subtle",
  "[&_ol]:my-3 [&_ol]:list-decimal [&_ol]:pl-5 [&_ol]:marker:text-wx-fg-subtle",
  "[&_li]:my-1",

  // ─── Task lists (read-only on widget side) ──────────────────────
  // TipTap's TaskList renders `<ul data-type="taskList">` with each
  // `<li data-type="taskItem" data-checked="…">` containing a
  // `<label><input type="checkbox"></label><div><p>text</p></div>`.
  // Default list rules above would paint a bullet *and* a checkbox,
  // and the inner `<p>` would force the text onto a second line.
  // These rules collapse it into a single Notion-style row with a
  // brand-tinted checkbox sticking left and the prose flowing
  // alongside. `pointer-events-none` on the input neuters interaction —
  // the widget renders authored content; visitors shouldn't be able
  // to tick someone else's todo.
  "[&_ul[data-type=taskList]]:list-none! [&_ul[data-type=taskList]]:pl-0!",
  "[&_ul[data-type=taskList]_li]:my-1.5 [&_ul[data-type=taskList]_li]:flex! [&_ul[data-type=taskList]_li]:items-start [&_ul[data-type=taskList]_li]:gap-2 [&_ul[data-type=taskList]_li]:pl-0",
  "[&_ul[data-type=taskList]_li]:marker:content-none",
  // Make the label its own line-height-matched flex box, then
  // centre the input inside it. With `inline-flex + items-center`
  // and the same line-height as the first row of text, the
  // checkbox sits visually centred against that first line — no
  // brittle pixel margin-tops. `h-5 leading-snug` matches the
  // surrounding text's row metrics; `items-start` on the parent
  // `<li>` keeps multi-line items from floating the box to the
  // middle of the row.
  "[&_ul[data-type=taskList]_li>label]:m-0 [&_ul[data-type=taskList]_li>label]:inline-flex [&_ul[data-type=taskList]_li>label]:h-5 [&_ul[data-type=taskList]_li>label]:items-center [&_ul[data-type=taskList]_li>label]:shrink-0 [&_ul[data-type=taskList]_li>label]:select-none",
  // Visible but unclickable — operator-authored state is the source
  // of truth, visitors can't toggle. `pointer-events: none` has to
  // go on the *label*, not just the `<input>`: HTML's spec makes
  // any click on a `<label>` forward to the wrapped input regardless
  // of `pointer-events` on the input itself. Disabling the label
  // neuters both surfaces.
  "[&_ul[data-type=taskList]_li>label]:pointer-events-none [&_ul[data-type=taskList]_li>label]:cursor-default",
  "[&_ul[data-type=taskList]_input]:accent-wx-primary [&_ul[data-type=taskList]_input]:h-3.5 [&_ul[data-type=taskList]_input]:w-3.5",
  "[&_ul[data-type=taskList]_li>label>span]:hidden",
  "[&_ul[data-type=taskList]_li>div]:min-w-0 [&_ul[data-type=taskList]_li>div]:flex-1",
  "[&_ul[data-type=taskList]_li>div>p]:my-0! [&_ul[data-type=taskList]_li>div>p]:leading-snug",
  "[&_ul[data-type=taskList]_li[data-checked=true]>div]:text-wx-fg-muted [&_ul[data-type=taskList]_li[data-checked=true]>div]:line-through",

  // ─── Quotes + rules ─────────────────────────────────────────────
  "[&_blockquote]:my-4 [&_blockquote]:border-l-2 [&_blockquote]:border-wx-primary/40",
  "[&_blockquote]:pl-3 [&_blockquote]:italic [&_blockquote]:text-wx-fg-muted",
  "[&_hr]:my-6 [&_hr]:border-wx-border",

  // ─── Images + figures ───────────────────────────────────────────
  // Bare image — no border, no rounded corners. Editorial photos
  // look like themselves. Figures keep their framed feel via the
  // `<figcaption>` rule below.
  "[&_img]:my-3 [&_img]:mx-auto [&_img]:block [&_img]:max-w-full",
  "[&_figure]:my-5 [&_figure]:flex [&_figure]:flex-col [&_figure]:items-center [&_figure]:text-center",
  "[&_figure_img]:my-0",
  "[&_figcaption]:mt-2 [&_figcaption]:text-xs [&_figcaption]:italic [&_figcaption]:text-wx-fg-muted",

  // ─── Tables ─────────────────────────────────────────────────────
  // shadcn-style: hairline `border` around the whole grid, header
  // tinted, alternate row tinting, padded cells. `table-fixed +
  // w-full` so columns split the available width evenly — short cells
  // ("1 / 2 / 3 / q / w / e") used to collapse to ~30 px, leaving the
  // rest of the table as dead whitespace. `min-w-full` keeps wide
  // content scrollable; the parent prose container provides the
  // horizontal scroll via `overflow-x-auto` (set on the article body).
  // Cell `<p>` reset prevents the editor's default `<p>` margins from
  // bloating cell height.
  "[&_table]:my-3 [&_table]:w-full [&_table]:table-fixed [&_table]:border-collapse [&_table]:text-xs",
  "[&_table]:overflow-hidden [&_table]:rounded-lg [&_table]:border [&_table]:border-wx-border",
  "[&_thead]:bg-wx-bg-elevated",
  // Tighter cell padding — the 12 × 8 baseline left a lot of
  // dead whitespace inside the widget's 420 px panel. 10 × 6 keeps
  // the table dense without sacrificing readability.
  "[&_th]:px-2.5 [&_th]:py-1.5 [&_th]:text-left [&_th]:font-medium [&_th]:text-wx-fg",
  "[&_th]:border-b [&_th]:border-wx-border",
  "[&_th+th]:border-l [&_th+th]:border-wx-border",
  "[&_td]:px-2.5 [&_td]:py-1.5 [&_td]:text-wx-fg [&_td]:align-top",
  "[&_td+td]:border-l [&_td+td]:border-wx-border",
  "[&_tbody_tr]:border-t [&_tbody_tr]:border-wx-border",
  "[&_tbody_tr:nth-child(odd)]:bg-wx-bg-elevated/40",
  // Strip every paragraph margin inside table cells. The TipTap
  // table cell wraps the text in a `<p>` and the default
  // `[&_p]:my-3` rule from this same prose class would push cell
  // content way out — turning each row into a tall band of empty
  // space (the "padding top and bottom" the user flagged). `inline`
  // collapses the paragraph entirely so the cell baselines align.
  "[&_th_p]:my-0 [&_td_p]:my-0 [&_th_p]:inline [&_td_p]:inline",

  // ─── Accordions (native `<details>`) ────────────────────────────
  // shadcn-accordion-style. Native disclosure marker is suppressed
  // (Webkit pseudo + `list-none` for Blink/Gecko) and we render our
  // own chevron via a CSS pseudo so we can rotate it on `[open]`.
  // Each accordion is a stacked card with hairline divider between
  // siblings.
  "[&_details]:my-2 [&_details]:overflow-hidden [&_details]:rounded-lg [&_details]:border [&_details]:border-wx-border [&_details]:bg-wx-bg-elevated/40",
  "[&_details+details]:mt-2",
  "[&_summary]:relative [&_summary]:cursor-pointer [&_summary]:list-none [&_summary]:px-4 [&_summary]:py-3",
  "[&_summary]:pr-10 [&_summary]:text-sm [&_summary]:font-medium [&_summary]:text-wx-fg",
  // Suppress the disclosure triangle across browsers. Webkit needs
  // the pseudo selector; Blink/Gecko honour `list-style: none` set
  // by `list-none` above, plus the explicit `marker` reset.
  "[&_summary::-webkit-details-marker]:hidden [&_summary::marker]:hidden",
  // Chevron — drawn with a unicode glyph rotated on open. `›`
  // pointing right when closed, down when open. Keeps the bundle
  // clean (no SVG asset for one icon).
  "[&_summary]:after:absolute [&_summary]:after:right-4 [&_summary]:after:top-1/2",
  "[&_summary]:after:-translate-y-1/2 [&_summary]:after:text-wx-fg-subtle",
  "[&_summary]:after:text-base [&_summary]:after:leading-none",
  "[&_summary]:after:transition-transform [&_summary]:after:content-['\\203A']",
  "[&_details[open]_summary]:after:rotate-90",
  // Body sits below the divider when open.
  "[&_details[open]_summary]:border-b [&_details[open]_summary]:border-wx-border",
  "[&_details]:[&>:not(summary)]:px-4 [&_details]:[&>:not(summary)]:py-3",
  "[&_details]:[&>:not(summary):first-of-type]:pt-3",

  // Tabs / accordion are no longer DOM-styled here — `ArticleHtml`
  // owns those, rendering proper React components (`TabsBlock`,
  // `AccordionBlock`) via `html-react-parser`. The native `<details>`
  // rules above are kept for RSS-ingested HTML that didn't go through
  // the operator's TipTap editor.
].join(" ");
