"use client";

import { ChevronDown } from "lucide-react";
import { useTranslations } from "next-intl";
import { useState } from "react";
import type { TocEntry } from "@/lib/article-toc";
import { cn } from "@/lib/utils";

/**
 * Intercom-style minimal TOC. The earlier "motion designer" version
 * (pulsing brand stripe, sliding rail, hover dots) was visually noisy
 * for a documentation surface — readers came for the outline, not a
 * showcase. This rebuild strips back to:
 *
 *   • "Table of contents" header + chevron, hairline divider.
 *   • Plain rows of clickable entries indented by heading level.
 *   • Subtle hover background; no active highlight, no marker.
 *
 * The aggressive prose-class resets (`[&_a]:no-underline`,
 * `[&_ul]:list-none`, `[&_li]:m-0`) stay — the card sits inside the
 * article prose container, which would otherwise paint anchor
 * underlines and disc bullets straight onto our nav.
 *
 * Click handler: previous attempts walked up looking for an ancestor
 * with overflow-y + scrollHeight > clientHeight, but the widget's
 * panel mounts the article body inside a shadcn `ScrollArea` whose
 * Radix Viewport carries `data-slot="scroll-area-viewport"`. We
 * target that explicitly first — the data-slot is the canonical
 * scroll anchor on every help / news article view — and only fall
 * back to a generic overflow walk for embeds that don't use
 * ScrollArea (e.g. the FE app's article preview cards).
 */
export function TableOfContents({ entries }: { entries: TocEntry[] }) {
  const t = useTranslations("article");
  // Default to closed. The card lives above the article body and
  // long-form posts already have a hero / title section that orients
  // the reader — surfacing the outline by default would dominate the
  // top of the panel. Readers who want it open one tap away.
  const [open, setOpen] = useState(false);

  const handleClick = (e: React.MouseEvent | React.KeyboardEvent, id: string) => {
    e.preventDefault();

    // The widget renders inside a Shadow DOM, so
    // `document.getElementById` returns null — shadow boundaries
    // are opaque to document queries. Use `getRootNode()` on the
    // click target to retrieve whichever root actually owns this
    // tree (the widget's ShadowRoot in the embed, or `document` for
    // tests / dashboard preview), then querySelector inside that
    // root. Falling back to `document` covers the unusual case
    // where `getRootNode` returns a fragment.
    const rootNode = (e.currentTarget as HTMLElement).getRootNode() as ShadowRoot | Document;
    const root: Document | ShadowRoot =
      rootNode instanceof ShadowRoot || rootNode instanceof Document ? rootNode : document;
    // Escape attribute-special characters in the id for the
    // selector — slugs only contain ASCII letters / digits / dashes
    // today, but defensive coding here is cheap.
    const target =
      "querySelector" in root
        ? (root.querySelector(`[id="${CSS.escape(id)}"]`) as HTMLElement | null)
        : null;
    if (!target) return;

    // 1. Prefer the shadcn `ScrollArea` viewport that wraps the
    //    article body — that's where the widget's scrolling
    //    actually lives. `closest()` walks up from the target and
    //    returns the first match. Inside a Shadow DOM `closest`
    //    works fine within the shadow tree.
    const scrollAreaViewport = target.closest(
      "[data-slot='scroll-area-viewport']",
    ) as HTMLElement | null;

    // 2. Fall back to a generic overflow walk for non-ScrollArea
    //    embeds (cards in the FE dashboard, RSS preview, etc).
    let scroller: HTMLElement | null = scrollAreaViewport;
    if (!scroller) {
      let cur: HTMLElement | null = target.parentElement;
      while (cur) {
        const cs = getComputedStyle(cur);
        if (/(auto|scroll|overlay)/.test(cs.overflowY)) {
          scroller = cur;
          break;
        }
        cur = cur.parentElement;
      }
    }

    const offsetPx = 16; // little air above the heading after scroll
    if (scroller) {
      const tRect = target.getBoundingClientRect();
      const sRect = scroller.getBoundingClientRect();
      scroller.scrollTo({
        top: scroller.scrollTop + tRect.top - sRect.top - offsetPx,
        behavior: "smooth",
      });
    } else {
      target.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  };

  return (
    <nav
      aria-label={t("tableOfContents")}
      className={cn(
        "wx-toc mt-0 overflow-hidden rounded-xl border border-wx-border bg-wx-bg",
        // Reset prose rules so the card's descendants don't inherit
        // anchor underline / disc markers / li margins.
        "[&_a]:no-underline [&_a]:text-inherit [&_a:hover]:opacity-100",
        "[&_ul]:m-0 [&_ul]:list-none [&_ul]:p-0",
        "[&_li]:m-0",
      )}
    >
      <button
        type="button"
        onClick={() => setOpen((v) => !v)}
        aria-expanded={open}
        className={cn(
          "flex w-full items-center justify-between gap-3 px-4 py-3",
          "text-left text-sm font-medium text-wx-fg",
          "transition-colors hover:bg-wx-bg-elevated/40",
        )}
      >
        <span>{t("tableOfContents")}</span>
        <ChevronDown
          className={cn(
            "h-4 w-4 shrink-0 text-wx-fg-subtle transition-transform duration-200",
            open && "rotate-180",
          )}
          aria-hidden="true"
        />
      </button>

      {/* Open/close via CSS grid rows so the divider + list slide
          in cleanly without a layout pop. */}
      <div
        className={cn(
          "grid transition-[grid-template-rows] duration-200 ease-out",
          open ? "grid-rows-[1fr]" : "grid-rows-[0fr]",
        )}
        aria-hidden={!open}
      >
        <div className="min-h-0 overflow-hidden">
          <div className="border-t border-wx-border/70 px-2 py-2">
            <div className="flex flex-col">
              {entries.map((entry) => {
                const indentPx = entry.level === 2 ? 16 : entry.level === 3 ? 32 : 0;
                return (
                  <button
                    key={entry.id}
                    type="button"
                    onClick={(e) => handleClick(e, entry.id)}
                    className={cn(
                      "flex h-8 items-center truncate rounded-md pr-2 text-left text-sm text-wx-fg",
                      "transition-colors hover:bg-wx-bg-elevated/50",
                    )}
                    style={{ paddingLeft: 12 + indentPx }}
                  >
                    <span className="truncate">{entry.text}</span>
                  </button>
                );
              })}
            </div>
          </div>
        </div>
      </div>
    </nav>
  );
}
