import { domToReact } from "html-react-parser";
import { cn } from "@/lib/utils";
import type { ReplaceHandler } from "./types";

/**
 * `<table>` → wrapped in a slim horizontal-scroll container. The native
 * browser scrollbar reads as a chunky grey rectangle that fights the
 * widget's premium chrome, so we paint our own track + thumb via WebKit
 * pseudos (Blink + Safari) and a Firefox `scrollbar-color` fallback.
 * 8 px height + soft rounded thumb matches the shadcn ScrollArea look
 * used on the editor side. The original `<table>` (and its attributes)
 * passes through untouched.
 */
export const tableHandler: ReplaceHandler = (node, ctx) => {
  if (node.name !== "table") return undefined;
  return (
    <div
      className={cn(
        "my-3 overflow-x-auto",
        "[scrollbar-width:thin] [scrollbar-color:var(--color-wx-fg-subtle)_transparent]",
        "[&::-webkit-scrollbar]:h-2",
        "[&::-webkit-scrollbar-track]:bg-transparent",
        "[&::-webkit-scrollbar-thumb]:rounded-full",
        "[&::-webkit-scrollbar-thumb]:bg-wx-fg-subtle/40",
        "[&::-webkit-scrollbar-thumb:hover]:bg-wx-fg-subtle/60",
      )}
    >
      <table>
        {domToReact((node.children ?? []) as Parameters<typeof domToReact>[0], ctx.options)}
      </table>
    </div>
  );
};
