import type { ReplaceHandler } from "./types";

/**
 * `<img>` — honour width + alignment. The operator's resize/align
 * controls store `width` (as a `%` value) and `data-align`
 * (`left | center | right`). We translate those into a small alignment
 * scheme:
 *   - `width: …`        — explicit width via inline style.
 *   - `data-align=left` — margin-right auto, image sits left.
 *   - `data-align=right`— margin-left auto, image sits right.
 *   - default / center  — both margins auto.
 * Bare image — no border, no rounded corners. Keeps editorial
 * photography looking like itself; `<figure>` wraps still get the
 * framed treatment via the prose `[&_figure_img]` rule.
 */
export const imageHandler: ReplaceHandler = (node, ctx) => {
  if (node.name !== "img") return undefined;
  const attrs = node.attribs ?? {};
  const align = attrs["data-align"] ?? "center";
  const width = attrs.width || attrs.style?.match(/width:\s*([^;]+)/i)?.[1];
  const marginLeft = align === "left" ? "0" : align === "right" ? "auto" : "auto";
  const marginRight = align === "right" ? "0" : align === "left" ? "auto" : "auto";
  const src = attrs.src ?? "";
  const alt = attrs.alt ?? "";

  const style = {
    ...(width ? { width } : {}),
    marginLeft,
    marginRight,
    display: "block",
  } as const;

  // Clickable when the caller wired a lightbox controller (article
  // views). Register this image in document order and open the gallery
  // at its index on tap. Without a controller (chat-bubble bodies) the
  // image renders inert, exactly as before.
  if (ctx.images && ctx.onImageClick) {
    const index = ctx.images.length;
    ctx.images.push({ url: src, mimetype: "image/jpeg", alt });
    const onImageClick = ctx.onImageClick;
    return (
      <button
        type="button"
        onClick={() => onImageClick(index)}
        className="my-3 block w-full cursor-zoom-in border-0 bg-transparent p-0"
        aria-label={alt || "Open image"}
      >
        {/* biome-ignore lint/performance/noImgElement: operator/RSS article images have arbitrary dimensions + remote hosts; next/image needs known sizes + an allowlist and isn't viable here */}
        <img src={src} alt={alt} style={style} className="max-w-full" />
      </button>
    );
  }

  return (
    // biome-ignore lint/performance/noImgElement: operator/RSS article images have arbitrary dimensions + remote hosts; next/image needs known sizes + an allowlist and isn't viable here
    <img src={src} alt={alt} style={style} className="my-3 max-w-full" />
  );
};
