/**
 * Slugify a heading's text content into an HTML id suitable for
 * `<a href="#…">` linking. ASCII letters / digits + dashes only;
 * Unicode passes through `latin1` normalisation when available so
 * accented characters fold to their base letters.
 *
 * Deduped against ids we've already seen — Strapi posts routinely
 * carry repeated section names ("Tips", "Conclusion") that would
 * otherwise generate colliding ids.
 */
export function slugifyHeading(text: string, seen: Set<string>): string {
  const base =
    text
      .normalize("NFD")
      .replace(/[̀-ͯ]/g, "") // strip combining marks
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "") || "section";
  let id = base;
  let i = 2;
  while (seen.has(id)) {
    id = `${base}-${i}`;
    i += 1;
  }
  seen.add(id);
  return id;
}

export interface TocEntry {
  id: string;
  text: string;
  /** 1 for `<h1>`, 2 for `<h2>`, 3 for `<h3>`. */
  level: number;
}
