import { Element } from "html-react-parser";

/**
 * Recursively collect the text content of a parsed element. Used to
 * derive heading slugs and tab labels from a node's children, skipping
 * element wrappers and concatenating only the raw text segments.
 */
export function extractText(node: Element): string {
  let out = "";
  for (const child of node.children ?? []) {
    if ((child as { type?: string }).type === "text") {
      out += (child as unknown as { data?: string }).data ?? "";
    } else if (child instanceof Element) {
      out += extractText(child);
    }
  }
  return out;
}
