"use client";

import { useApolloClient } from "@apollo/client/react";
import { motion } from "motion/react";
import { useTranslations } from "next-intl";
import { useCallback, useEffect, useMemo, useState } from "react";
import { ReactionSurface } from "@/lib/graphql/generated/types";
import {
  useSubmitVisitorReactionMutation,
  useVisitorReactionSetQuery,
} from "@/lib/graphql/queries/generated/reactions.generated";
import { cn } from "@/lib/utils";

interface ReactionBarProps {
  /** Which surface the operator's palette comes from. */
  surface: ReactionSurface;
  /** Article / post id the vote attaches to. */
  itemId: string;
  /** The visitor's OWN current reaction slotIndex on this item's
   *  translation group, from the BE (`viewerReaction` on the read query),
   *  or `null` when they haven't reacted. Authoritative in real mode —
   *  drives the active-emoji highlight, per-group + cross-device (once
   *  verified). Ignored in demo mode (no BE → localStorage instead). */
  viewerReaction?: number | null;
  /** Every cache id in this item's translation group (the item itself +
   *  its locale variants' ids). A reaction is per-GROUP on the BE, so each
   *  variant is a separate Apollo cache entry that must be updated together
   *  — otherwise switching locales shows a stale highlight/count until
   *  reload. Defaults to just `[itemId]`. */
  groupItemIds?: string[];
  /** Sparse `{ [slotIndex]: count }` map fetched alongside the entity.
   *  Operator may have removed a slot since the visitor last voted —
   *  stranded counts are ignored at render time (only slots present
   *  in the active set show up). */
  reactionCounts?: Record<string, number> | null;
  /** Disables submission (dummy mode + dashboard preview). The bar
   *  still renders with current counts so the operator sees the UX. */
  readonly?: boolean;
  /** Demo / dashboard-preview mode. Skips the live `reactionSet`
   *  config query (no network in demo) and renders a default emoji
   *  palette so the marketing/preview surface still shows the bar. */
  isDummy?: boolean;
  /** Operator's `messenger.showReactionCounts` toggle. When `false`,
   *  the bar still renders and remains tappable, but the per-emoji
   *  numeric tally next to each button is hidden. Defaults to `true`. */
  showCounts?: boolean;
  className?: string;
}

/** DEMO-ONLY local-storage key for the visitor's pick. In real mode the
 *  BE is the source of truth (`viewerReaction` on the read query), so we
 *  don't persist anything client-side. Demo has no BE, so it remembers the
 *  pick here to keep the active highlight across the session. */
const STORAGE_KEY = (surface: ReactionSurface, itemId: string) =>
  `wexio:reaction:${surface}:${itemId}`;

/** Default palette shown in demo / preview mode so the bar is visible
 *  without firing the live `reactionSet` query. Mirrors the BE's seed
 *  defaults (🎉 / ❤️ / 👍). */
const DEMO_REACTION_SLOTS: { slotIndex: number; emoji: string }[] = [
  { slotIndex: 0, emoji: "🎉" },
  { slotIndex: 1, emoji: "❤️" },
  { slotIndex: 2, emoji: "👍" },
];

/** Reaction surface → the GraphQL `__typename` of the entity it attaches
 *  to. Used to address the right normalized cache entries when fanning a
 *  vote out across a translation group. */
const REACTION_TYPENAME: Record<ReactionSurface, string> = {
  [ReactionSurface.NEWS]: "NewsPost",
  [ReactionSurface.HELP]: "HelpArticle",
};

/**
 * Operator-configured emoji reaction palette. Fetches
 * `reactionSet(surface)` once (cached at the Apollo level — emoji
 * palette is org-wide and rarely changes), renders one button per
 * enabled slot, and submits via `submitVisitorReaction`.
 *
 * Visitor semantics: one vote per item (per translation group), lifetime.
 * Re-tap same slot = no-op. Tap a different slot moves the vote (BE
 * decrements prior, increments new). The active highlight comes from the
 * BE's `viewerReaction` (authoritative, cross-device once verified) — the
 * `viewerReaction` prop. Demo mode falls back to `localStorage`.
 */
export function ReactionBar({
  surface,
  itemId,
  reactionCounts,
  viewerReaction,
  groupItemIds,
  readonly = false,
  showCounts = true,
  isDummy = false,
  className,
}: ReactionBarProps) {
  const t = useTranslations("reactions");
  const client = useApolloClient();

  const { data, loading } = useVisitorReactionSetQuery({
    variables: { surface },
    fetchPolicy: "cache-first",
    // Demo / preview: render the default palette without a network
    // round-trip. The live query is operator-config that demo doesn't
    // have, so firing it would be a pointless request.
    skip: isDummy,
  });
  const [submit, { loading: submitting }] = useSubmitVisitorReactionMutation();

  const slots: { slotIndex: number; emoji: string }[] = useMemo(
    () => (isDummy ? DEMO_REACTION_SLOTS : (data?.visitorReactionSet?.slots ?? [])),
    [isDummy, data],
  );
  const enabled = isDummy ? true : (data?.visitorReactionSet?.enabled ?? true);

  // The visitor's current pick. `null` = no vote yet; otherwise the
  // slotIndex. Real mode seeds from the BE's `viewerReaction` (canonical,
  // per translation group, cross-device once verified). Demo mode has no
  // BE, so it remembers the pick in localStorage for the session.
  const storageKey = STORAGE_KEY(surface, itemId);
  const [pickedSlot, setPickedSlot] = useState<number | null>(null);
  useEffect(() => {
    if (!isDummy) {
      setPickedSlot(viewerReaction ?? null);
      return;
    }
    if (typeof window === "undefined") return;
    const raw = window.localStorage.getItem(storageKey);
    setPickedSlot(raw === null ? null : Number(raw));
  }, [isDummy, storageKey, viewerReaction]);

  // Demo-only optimistic counts. Real mode drives counts through the
  // Apollo cache (so every locale variant in the translation group stays
  // in sync), so it doesn't use this local delta.
  const [optimisticCounts, setOptimisticCounts] = useState<Record<number, number>>({});
  const countFor = (slotIndex: number): number => {
    const base =
      (reactionCounts as Record<string, number> | null | undefined)?.[String(slotIndex)] ?? 0;
    return base + (isDummy ? (optimisticCounts[slotIndex] ?? 0) : 0);
  };

  // Move the visitor's vote in the cache for EVERY id in the translation
  // group: set `viewerReaction = to`, `+1` on `to`, `-1` on `from`. Reads
  // (single / list / related) of any variant re-render from this, so the
  // highlight + counts stay correct across locale switches without a
  // refetch. Passing `from`/`to` swapped reverts the move.
  const applyVoteToCache = useCallback(
    (from: number | null, to: number | null) => {
      const typename = REACTION_TYPENAME[surface];
      const ids = groupItemIds?.length ? groupItemIds : [itemId];
      for (const id of ids) {
        const cacheId = client.cache.identify({ __typename: typename, _id: id });
        if (!cacheId) continue;
        client.cache.modify({
          id: cacheId,
          fields: {
            viewerReaction: () => to,
            // Apollo types a JSON-scalar field's value broadly
            // (Reference | StoreObject); it's actually our `{ slot: count }`
            // map. Cast in, return a plain map out.
            reactionCounts: (existing: unknown) => {
              const next = { ...((existing as Record<string, number> | null) ?? {}) };
              if (to !== null) next[to] = (next[to] ?? 0) + 1;
              if (from !== null) next[from] = Math.max(0, (next[from] ?? 0) - 1);
              return next;
            },
          },
        });
      }
    },
    [client, surface, groupItemIds, itemId],
  );

  const handleTap = async (slotIndex: number) => {
    if (readonly || submitting) return;
    if (pickedSlot === slotIndex) return; // no-op on re-tap
    const prior = pickedSlot;
    setPickedSlot(slotIndex);

    // Demo / preview: no BE — persist the pick locally + apply the local
    // optimistic count delta. The bar stays fully interactive.
    if (isDummy) {
      if (typeof window !== "undefined") {
        window.localStorage.setItem(storageKey, String(slotIndex));
      }
      setOptimisticCounts((prev) => ({
        ...prev,
        [slotIndex]: (prev[slotIndex] ?? 0) + 1,
        ...(prior !== null ? { [prior]: (prev[prior] ?? 0) - 1 } : {}),
      }));
      return;
    }

    // Real: fan the vote into the cache for the whole group, then submit.
    // Roll the cache back on failure.
    applyVoteToCache(prior, slotIndex);
    try {
      await submit({ variables: { input: { surface, itemId, slotIndex } } });
    } catch {
      applyVoteToCache(slotIndex, prior);
      setPickedSlot(prior);
    }
  };

  // Operator disabled reactions for this surface, or set is still
  // loading on the first render → don't paint anything yet.
  if (loading || !enabled || slots.length === 0) return null;

  return (
    // biome-ignore lint/a11y/useSemanticElements: `<fieldset>` carries default border/margin chrome that would alter this inline strip's layout — a div with role="group" is the intended, style-neutral grouping
    <div
      className={cn(
        // Center-aligned, transparent strip — sits inline with the
        // article content (no panel chrome). Larger emoji + tap
        // surface than the list-card chip variant.
        "flex flex-wrap items-center justify-center gap-2",
        className,
      )}
      role="group"
      aria-label={t("ariaLabel")}
    >
      {slots.map((slot) => {
        const active = pickedSlot === slot.slotIndex;
        const count = countFor(slot.slotIndex);
        return (
          <motion.button
            key={slot.slotIndex}
            type="button"
            disabled={readonly || submitting}
            onClick={() => void handleTap(slot.slotIndex)}
            whileTap={{ scale: 0.9 }}
            whileHover={{ scale: 1.06 }}
            transition={{ type: "spring", stiffness: 400, damping: 18 }}
            className={cn(
              "flex items-center gap-1.5 rounded-full px-3 py-1.5 text-2xl leading-none transition-colors",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary",
              active ? "bg-wx-primary/10 ring-1 ring-wx-primary/40" : "hover:bg-wx-bg-elevated",
              readonly && "cursor-default opacity-70",
            )}
            aria-pressed={active}
            aria-label={t("tapAria", { emoji: slot.emoji })}
          >
            <span aria-hidden="true">{slot.emoji}</span>
            {showCounts && count > 0 && (
              <span className="text-xs font-medium text-wx-fg-muted">{count}</span>
            )}
          </motion.button>
        );
      })}
    </div>
  );
}
