import { domToReact } from "html-react-parser";
import type { ReplaceHandler } from "./types";

/**
 * `<a>` — always open externally with a safe `rel`. Any operator-set
 * `target` is stripped in favour of `_blank`.
 */
export const linkHandler: ReplaceHandler = (node, ctx) => {
  if (node.name !== "a") return undefined;
  const href = node.attribs?.href ?? "";
  return (
    <a
      href={href}
      target="_blank"
      rel="noopener noreferrer"
      className="text-wx-primary underline underline-offset-2 transition-opacity hover:opacity-70"
    >
      {domToReact((node.children ?? []) as Parameters<typeof domToReact>[0], ctx.options)}
    </a>
  );
};
