import { Element, type HTMLReactParserOptions } from "html-react-parser";
import type { LightboxItem } from "@/components/widget/tabs/messages-tab/message/media-lightbox";
import type { TocEntry } from "@/lib/article-toc";
import { accordionHandler } from "./build-options/accordion";
import { customElementHandler } from "./build-options/custom-element";
import { headingHandler } from "./build-options/heading";
import { imageHandler } from "./build-options/image";
import { linkHandler } from "./build-options/link";
import { tableHandler } from "./build-options/table";
import { tabsHandler } from "./build-options/tabs";
import type { ReplaceContext, ReplaceHandler } from "./build-options/types";

/**
 * Ordered tag → React mappings. Headings run first (they collect the
 * TOC), then the block-level custom mappings, then inline links. The
 * first handler to return a node wins; anything that returns `undefined`
 * falls through to the next handler and finally the parser's default
 * mapping (paragraphs, lists, code, figures, …).
 */
const HANDLERS: ReplaceHandler[] = [
  headingHandler,
  tabsHandler,
  accordionHandler,
  // Custom block-level tags like `<card>` / `<callout>` / `<note>` —
  // emitted by Tiptap "info-box" extensions on the authoring side.
  // Runs before the table / image / link handlers so a callout's
  // children still flow through them via the recursive `domToReact`.
  customElementHandler,
  tableHandler,
  imageHandler,
  linkHandler,
];

/**
 * Build the `html-react-parser` options. The `replace` callback recurses
 * through `domToReact`, which needs the same options reference back so
 * nested children also get the heading-id treatment + custom node
 * mappings — hence `options` is declared first, then its `replace`
 * assigned so the closure (and the handler context) share one identity.
 */
export function buildOptions(
  entries: TocEntry[],
  seenIds: Set<string>,
  images?: LightboxItem[],
  onImageClick?: (index: number) => void,
): HTMLReactParserOptions {
  const options: HTMLReactParserOptions = {} as HTMLReactParserOptions;
  const ctx: ReplaceContext = { options, entries, seenIds, images, onImageClick };
  options.replace = (node) => {
    if (!(node instanceof Element)) return undefined;
    for (const handler of HANDLERS) {
      const result = handler(node, ctx);
      if (result !== undefined) return result;
    }
    return undefined;
  };
  return options;
}
