import { domToReact } from "html-react-parser";
import { createElement } from "react";
import { slugifyHeading } from "@/lib/article-toc";
import { extractText } from "../extract-text";
import type { ReplaceHandler } from "./types";

/**
 * Heading IDs + TOC collection. Slugify the text of every h1 / h2 / h3,
 * push onto the `entries` accumulator the context exposes, then render
 * the heading with the generated id so anchor links work. We only
 * collect 1-3 — h4+ rarely appears in operator content and would bloat
 * the dropdown. Empty-text headings fall through to the default mapping.
 */
export const headingHandler: ReplaceHandler = (node, ctx) => {
  if (node.name !== "h1" && node.name !== "h2" && node.name !== "h3") {
    return undefined;
  }
  const level = Number(node.name.slice(1));
  const text = extractText(node).trim();
  if (!text) return undefined;
  const id = slugifyHeading(text, ctx.seenIds);
  ctx.entries.push({ id, text, level });
  return createElement(
    node.name,
    { id },
    domToReact((node.children ?? []) as Parameters<typeof domToReact>[0], ctx.options),
  );
};
