"use client";

import { useEffect } from "react";

/**
 * Surface the active article's title up to the widget shell's sticky
 * header (it renders the title as a breadcrumb on article routes).
 *
 * Sets the title on mount and clears it (`null`) on unmount. This
 * mount/unmount ownership — rather than the shell clearing on every
 * route change — is what makes both back-navigation AND Apollo
 * cache-hit re-opens reset the header deterministically: each fresh
 * mount sets the current title, and the previous unmount has already
 * wiped the stale one, so React's batch ordering can't drop the title
 * back to the tab name.
 *
 * Shared by the help + news article views, which had identical copies.
 */
export function useArticleTitleSink(
  title: string | undefined,
  onTitleResolved?: (title: string | null) => void,
): void {
  useEffect(() => {
    if (!onTitleResolved) return;
    if (title) onTitleResolved(title);
    return () => onTitleResolved(null);
  }, [title, onTitleResolved]);
}
