"use client";

import { ChevronDown } from "lucide-react";
import { type ReactNode, useState } from "react";
import { cn } from "@/lib/utils";

/**
 * Collapsible disclosure rendered for `<details>` / TipTap
 * `<div data-type="details">`. Owns its own open state and renders its
 * own chevron toggle (the source markup's native toggle is stripped by
 * the accordion handler).
 */
export function AccordionBlock({
  summary,
  body,
  defaultOpen,
}: {
  summary: ReactNode;
  body: ReactNode;
  defaultOpen: boolean;
}) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="my-2 overflow-hidden rounded-lg border border-wx-border">
      <button
        type="button"
        onClick={() => setOpen((v) => !v)}
        aria-expanded={open}
        className={cn(
          "flex w-full items-center justify-between gap-3 px-4 py-3",
          // Bold title for visual prominence — matches typical
          // accordion patterns (FAQ-style) where the question is
          // bolder than the answer.
          "text-left text-sm font-semibold text-wx-fg",
          "transition-colors hover:bg-wx-bg-elevated/50",
          "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary/30",
        )}
      >
        <span className="min-w-0 flex-1">{summary}</span>
        <ChevronDown
          className={cn(
            "h-4 w-4 shrink-0 text-wx-fg-subtle transition-transform",
            open && "rotate-180",
          )}
          aria-hidden="true"
        />
      </button>
      {open && (
        // `[&>:first-child]:mt-0` strips the top margin of the first
        // body paragraph so the divider + body read as one unit
        // without an awkward gap.
        <div className="border-t border-wx-border px-4 py-3 text-sm leading-relaxed text-wx-fg [&>:first-child]:mt-0 [&>:last-child]:mb-0">
          {body}
        </div>
      )}
    </div>
  );
}
