"use client";

import { useEffect, useState } from "react";
import type { DemoTranslator } from "@/dummy/translator";

/**
 * Locales the bundled demo content ships in. Both `demo.<locale>.json`
 * files carry the FULL article set, so every demo article exists in each
 * of these — which is exactly what powers the in-demo, article-scoped
 * language switcher.
 */
export const DEMO_LOCALES = ["en", "uk"] as const;

/** Per-locale dynamic import so each demo bundle is its own chunk,
 *  fetched only when the visitor actually switches to that language. */
async function loadDemoBundle(locale: string): Promise<Record<string, unknown>> {
  switch (locale) {
    case "uk":
      return (await import("@/messages/demo.uk.json")).default;
    default:
      return (await import("@/messages/demo.en.json")).default;
  }
}

/**
 * Resolve a dot-path into the demo bundle and return the raw value
 * (string, array, or object) — exactly what next-intl's `t.raw()` does
 * for our demo keys, but without going through next-intl (its
 * `createTranslator` expects the app's locale config and throws on a
 * standalone bundle). Keys split on `.` only, so hyphenated ids like
 * `demo-news-1` stay intact.
 */
export function rawFromBundle(bundle: Record<string, unknown>): DemoTranslator["raw"] {
  return (key: string): unknown => {
    let cursor: unknown = bundle;
    for (const segment of key.split(".")) {
      if (cursor && typeof cursor === "object" && segment in (cursor as Record<string, unknown>)) {
        cursor = (cursor as Record<string, unknown>)[segment];
      } else {
        return undefined;
      }
    }
    return cursor;
  };
}

/**
 * A `DemoTranslator` for an ARBITRARY locale, loaded on demand. Powers
 * the article-scoped language switch in demo mode: the visitor picks a
 * language and we render that one article's content from the matching
 * demo bundle WITHOUT touching the widget's own locale. Returns
 * `fallback` (the widget-locale translator) until the requested bundle
 * lands, so the article never flashes empty.
 */
export function useDemoTranslator(locale: string, fallback: DemoTranslator): DemoTranslator {
  const [translator, setTranslator] = useState<DemoTranslator | null>(null);

  useEffect(() => {
    let active = true;
    loadDemoBundle(locale).then((messages) => {
      if (!active) return;
      setTranslator({ raw: rawFromBundle(messages) });
    });
    return () => {
      active = false;
    };
  }, [locale]);

  return translator ?? fallback;
}
