/**
 * Returns `true` when `content` looks like HTML (TipTap-authored,
 * RSS `<content:encoded>`) rather than markdown.
 *
 * The widget's article surfaces don't trust the BE-side `bodyFormat`
 * field exclusively — native posts authored in the operator's
 * TipTap editor always produce HTML, but historically saved as
 * `bodyFormat: 'markdown'` (the default). RSS ingest correctly
 * stamps `'html'` for `<content:encoded>` items but `'markdown'`
 * for `description`-only feeds, even when the description is HTML.
 *
 * Heuristic: a leading `<` followed by a tag-letter opens an
 * element. We tolerate leading whitespace + `<!doctype>` / comments
 * so RSS-cleaned HTML still trips the detector. False negatives
 * (HTML that starts with raw text before any tag) are rare and
 * harmless — ReactMarkdown's `remark-gfm` renders inline tags
 * fine, just no custom `<details>` / `<div data-type=tabs>` magic.
 */
export function looksLikeHtml(content: string | null | undefined): boolean {
  if (!content) return false;
  const sample = content.trimStart().slice(0, 200);
  // Tag opener — `<` followed by a tag letter, OR a doctype / comment
  // / cdata that we'd still want to treat as HTML.
  return /^<(?:[a-z!][^>]*|!--)/i.test(sample);
}
