import { domToReact, Element } from "html-react-parser";
import { AccordionBlock } from "../blocks/accordion-block";
import type { ReplaceHandler } from "./types";

/**
 * Accordion. Two shapes are catchable here:
 *   1. **Native `<details>`** — emitted by RSS HTML, older posts
 *      authored before we wired the TipTap Details extension, or any
 *      external HTML pasted into the editor.
 *   2. **TipTap v3 `<div data-type="details">`** — produced by
 *      `@tiptap/extension-details`. Wraps everything in a `<div>` shell
 *      with `<summary>` + `<div data-type="detailsContent">` nested
 *      under another inner `<div>` (the NodeView's render target).
 *      Sometimes a `<button>` toggle sits at the top of the shell —
 *      strip it: `AccordionBlock` renders its own toggle.
 */
export const accordionHandler: ReplaceHandler = (node, ctx) => {
  const isNativeDetails = node.name === "details";
  const isTipTapDetails = node.name === "div" && node.attribs?.["data-type"] === "details";
  if (!isNativeDetails && !isTipTapDetails) return undefined;

  // Walk through the immediate descendants looking for the `<summary>`
  // and the body. The TipTap shell adds extra wrapper divs, so we search
  // recursively (capped to a single level so we don't strip unrelated
  // nested content).
  const allChildren: unknown[] = isTipTapDetails
    ? (node.children ?? []).flatMap((c) =>
        c instanceof Element && c.name === "div" && !c.attribs?.["data-type"]
          ? (c.children ?? [])
          : [c],
      )
    : (node.children ?? []);
  const summaryEl = allChildren.find(
    (c): c is Element => c instanceof Element && c.name === "summary",
  );
  const rawBodyEls = allChildren.filter(
    (c) =>
      c !== summaryEl &&
      // Skip the TipTap NodeView's toggle button — we render our own
      // chevron inside `AccordionBlock`.
      !(c instanceof Element && c.name === "button"),
  );
  // Unwrap `<div data-type="detailsContent">` (or kebab-case alias from
  // older versions) so the body is the actual paragraphs, not the
  // wrapper div which carries `[hidden]`.
  const detailsContentWrapper = rawBodyEls.find(
    (c): c is Element =>
      c instanceof Element &&
      c.name === "div" &&
      (c.attribs?.["data-type"] === "detailsContent" ||
        c.attribs?.["data-type"] === "details-content"),
  );
  const bodyEls = detailsContentWrapper ? (detailsContentWrapper.children ?? []) : rawBodyEls;
  const summary = summaryEl
    ? domToReact(summaryEl.children as Parameters<typeof domToReact>[0], ctx.options)
    : null;
  const body = <>{domToReact(bodyEls as Parameters<typeof domToReact>[0], ctx.options)}</>;
  // Open state: native uses `[open]` attribute; TipTap v3 uses
  // `data-open` on the wrapper. Either flips the initial render to
  // expanded; otherwise the accordion starts collapsed.
  const initiallyOpen = node.attribs?.open !== undefined || node.attribs?.["data-open"] === "true";
  return <AccordionBlock defaultOpen={initiallyOpen} summary={summary} body={body} />;
};
