"use client";

import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { ARTICLE_PROSE_CLASSES } from "@/lib/article-prose";
import { ArticleHtml } from "./article-html";

/**
 * Shared prose container for the help + news article bodies (they had
 * near-identical copies).
 *
 * HTML content goes through `ArticleHtml`, which parses the markup into
 * a React tree (tabs, accordions, table-scroll wrapper, links). Markdown
 * content keeps the `react-markdown` + `remark-gfm` pipeline so RSS feeds
 * that ship plain markdown still render.
 *
 * The HTML path always pins `mt-0`; the markdown path's top margin is the
 * only per-surface difference (help `mt-5`, news `mt-3`), so the caller
 * passes just that margin class — every other prose class is identical.
 */
export function ArticleBody({
  content,
  isHtml,
  markdownMarginClass,
}: {
  content: string;
  isHtml: boolean;
  markdownMarginClass: string;
}) {
  if (isHtml) {
    return <ArticleHtml html={content} className={`mt-0 ${ARTICLE_PROSE_CLASSES}`} />;
  }
  return (
    <div className={`${markdownMarginClass} ${ARTICLE_PROSE_CLASSES}`}>
      <ReactMarkdown remarkPlugins={[remarkGfm]}>{content}</ReactMarkdown>
    </div>
  );
}
