"use client";

import { Check, ChevronDown, Globe } from "lucide-react";
import { AnimatePresence, motion } from "motion/react";
import { useTranslations } from "next-intl";
import { useEffect, useRef, useState } from "react";
import { cn } from "@/lib/utils";
import { languageName } from "./helpers";

interface LanguageSelectorProps {
  /** Locale of the article currently on screen — its row renders with a
   *  check and the trigger shows its name. */
  currentLocale: string;
  /** Every published locale variant of the article, INCLUDING the
   *  current one. The selector hides itself when there's nothing to
   *  switch to (a single language). */
  locales: string[];
  /** Visitor picked a language → switch to that variant. */
  onSelect: (locale: string) => void;
  className?: string;
}

/**
 * Below-article language switcher (Help + News). A compact dropdown:
 * the trigger shows the current language; opening it lists every
 * published locale variant. Picking one switches the article to that
 * language (article-scoped — it never changes the widget's own locale).
 * Hidden entirely when the article exists in only one language.
 *
 * Language labels come from `Intl.DisplayNames` (each shown in its own
 * script) — no per-language i18n keys to maintain. Only the section
 * heading is translated.
 */
export function LanguageSelector({
  currentLocale,
  locales,
  onSelect,
  className,
}: LanguageSelectorProps) {
  const t = useTranslations("languageSelector");
  const [open, setOpen] = useState(false);
  const rootRef = useRef<HTMLDivElement>(null);

  // Close on outside-click + Escape. Bound only while open.
  useEffect(() => {
    if (!open) return;
    const onPointer = (e: MouseEvent) => {
      if (rootRef.current && !rootRef.current.contains(e.target as Node)) setOpen(false);
    };
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") setOpen(false);
    };
    document.addEventListener("mousedown", onPointer);
    document.addEventListener("keydown", onKey);
    return () => {
      document.removeEventListener("mousedown", onPointer);
      document.removeEventListener("keydown", onKey);
    };
  }, [open]);

  // De-dupe defensively and bail when there's only one language.
  const unique = Array.from(new Set(locales.filter(Boolean)));
  if (unique.length <= 1) return null;
  const currentBase = currentLocale.split("-")[0].toLowerCase();

  return (
    <div ref={rootRef} className={cn("relative", className)}>
      <p className="mb-1.5 text-xs font-semibold tracking-wide text-wx-fg-muted uppercase">
        {t("title")}
      </p>
      <button
        type="button"
        onClick={() => setOpen((o) => !o)}
        aria-haspopup="listbox"
        aria-expanded={open}
        aria-label={t("ariaLabel")}
        className={cn(
          "flex w-full items-center gap-2 rounded-wx-sm border border-wx-border bg-wx-bg px-3 py-2",
          "text-sm font-medium text-wx-fg transition-colors hover:bg-wx-bg-elevated",
          "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary",
        )}
      >
        <Globe size={15} className="shrink-0 text-wx-fg-muted" />
        <span className="min-w-0 flex-1 truncate text-left">{languageName(currentLocale)}</span>
        <ChevronDown
          size={15}
          className={cn("shrink-0 text-wx-fg-subtle transition-transform", open && "rotate-180")}
        />
      </button>

      <AnimatePresence>
        {open && (
          <motion.ul
            initial={{ opacity: 0, y: 4 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 4 }}
            transition={{ duration: 0.14 }}
            // Opens upward — the selector sits low in the article, so a
            // downward menu would clip against the related/footer rows.
            className={cn(
              "absolute bottom-full left-0 z-20 mb-1 max-h-56 w-full overflow-auto",
              "rounded-wx-sm border border-wx-border bg-wx-bg py-1 shadow-[0_12px_32px_rgba(0,0,0,0.16)]",
            )}
            role="listbox"
          >
            {unique.map((loc) => {
              const active = loc.split("-")[0].toLowerCase() === currentBase;
              return (
                <li key={loc}>
                  <button
                    type="button"
                    role="option"
                    aria-selected={active}
                    onClick={() => {
                      onSelect(loc);
                      setOpen(false);
                    }}
                    className={cn(
                      "flex w-full items-center gap-2 px-3 py-2 text-left text-sm transition-colors",
                      active
                        ? "font-semibold text-wx-primary"
                        : "text-wx-fg hover:bg-wx-bg-elevated",
                    )}
                  >
                    <span className="min-w-0 flex-1 truncate">{languageName(loc)}</span>
                    {active && <Check size={15} className="shrink-0 text-wx-primary" />}
                  </button>
                </li>
              );
            })}
          </motion.ul>
        )}
      </AnimatePresence>
    </div>
  );
}
