"use client";

import { useTranslations } from "next-intl";
import { type ReactNode, useState } from "react";
import { cn } from "@/lib/utils";

/**
 * Underline-indicator tab bar — Material / GitHub / Notion style.
 * Text-only triggers, the active one carries weight + a 2-px
 * brand-coloured underline that slides between tabs. Visually quiet but
 * very recognisable.
 *
 * Labels fall back to a translated "Tab {n}" when the source markup
 * didn't carry a `[data-tab-label]`.
 */
export function TabsBlock({ tabs }: { tabs: { label: string; body: ReactNode }[] }) {
  const t = useTranslations("article");
  const [active, setActive] = useState(0);
  if (tabs.length === 0) return null;
  return (
    <div className="my-4">
      {/* Underline-indicator tab bar — Material / GitHub / Notion
          style. Text-only triggers, active one carries weight + a
          2-px brand-coloured underline that slides between tabs.
          Visually quiet but very recognisable. */}
      <div role="tablist" className="relative flex items-center gap-1 border-b border-wx-border">
        {tabs.map((tab, idx) => {
          const isActive = idx === active;
          const label = tab.label || t("tabFallback", { n: idx + 1 });
          return (
            <button
              // biome-ignore lint/suspicious/noArrayIndexKey: tabs are parsed once from static markup — never reordered, inserted, or filtered, so the index is a stable key
              key={idx}
              type="button"
              role="tab"
              aria-selected={isActive}
              tabIndex={isActive ? 0 : -1}
              onClick={() => setActive(idx)}
              className={cn(
                "group relative inline-flex items-center justify-center px-3 py-2 text-sm",
                "transition-colors focus-visible:outline-none",
                isActive
                  ? "font-semibold text-wx-fg"
                  : "font-medium text-wx-fg-muted hover:text-wx-fg",
              )}
            >
              {label}
              {/* The underline. Always rendered (scale-x:0 when
                  inactive) so the visitor sees it ease into the new
                  position on click — no layout jump, just a slide.
                  origin-left keeps the animation directional. */}
              <span
                aria-hidden="true"
                className={cn(
                  "pointer-events-none absolute inset-x-2 bottom-0 h-[2px] origin-left rounded-full bg-wx-primary",
                  "transition-transform duration-200 ease-out",
                  isActive ? "scale-x-100" : "scale-x-0",
                )}
              />
            </button>
          );
        })}
      </div>
      {/* Panel — no card frame; flows with prose. `mt-3` for visual
          separation from the underline. First/last margins inside
          stripped so paragraphs don't double-up against the tab bar
          or the next block below. */}
      <div className="mt-3 text-sm leading-relaxed text-wx-fg [&>:first-child]:mt-0 [&>:last-child]:mb-0">
        {tabs[active]?.body}
      </div>
    </div>
  );
}
