export type WaitTimeoutCardData = {
  __typename?: 'WaitTimeoutCardData';
  /** Optional nudge text sent on each retry tick. Reuses the standard `input` field shared by TEXT_CARD and friends. Supports {{variable}} interpolation. Behavior depends on `retryResendCard`: (input set, retryResendCard=false/unset) → nudge only; (input set, retryResendCard=true) → nudge then re-send the preceding card; (input unset) → re-send the preceding card (retryResendCard ignored — there is nothing else to send). */
  input?: Maybe<Scalars['String']['output']>;
  /** Number of re-sends of the preceding card before final timeout. Default 0 (no retries — first timeout is final). Max 10. Total sends = 1 + retries. Not allowed for AI_AGENT / WA_CATALOG / WA_PRODUCT / WA_PRODUCTS cards. */
  retries?: Maybe<Scalars['Float']['output']>;
  /** Whether to also re-send the preceding card on each retry tick when `input` is set. False (default) → nudge only; true → nudge then re-send. Ignored when `input` is unset (we always re-send in that case). Not allowed for AI_AGENT / WA_CATALOG / WA_PRODUCT / WA_PRODUCTS cards (same reason as `retries`). */
  retryResendCard?: Maybe<Scalars['Boolean']['output']>;
  /** Seconds before the deadline fires. Min 60, max 30 days (2_592_000). Required at publish time. */
  timeoutSeconds?: Maybe<Scalars['Float']['output']>;
};

