/**
 * Human-readable autonym for a BCP-47 locale code — the language's
 * name written in its OWN language/script:
 *   "en"     → "English"
 *   "uk"     → "Українська"
 *   "de-DE"  → "Deutsch"
 *
 * Uses the platform `Intl.DisplayNames` (available in every browser
 * the widget targets + Node) resolved IN the target locale, so each
 * chip reads natively. Falls back to the uppercased base code when the
 * runtime can't resolve the name (unknown / malformed code).
 */
export function languageName(locale: string): string {
  const base = locale.split("-")[0];
  try {
    const dn = new Intl.DisplayNames([locale], { type: "language" });
    const name = dn.of(base);
    // `Intl.DisplayNames.of` returns the input code unchanged when it
    // can't resolve it — treat that as a miss and fall through.
    if (name && name.toLowerCase() !== base.toLowerCase()) {
      return name.charAt(0).toUpperCase() + name.slice(1);
    }
  } catch {
    // Older runtime without Intl.DisplayNames — fall through.
  }
  return base.toUpperCase();
}
